#include "script_bytecode.h"
#include <stdio.h>
static void pv(YaatValue *v){ printf("{\"kind\":%d,\"bool\":%d,\"int\":%d,\"string\":\"%s\"}", v->kind, v->bool_value?1:0, v->int_value, v->string_value); }
int main(int argc,char**argv){ YaatScriptPackage p; int i,j,k; if(argc<2||!yaat_bytecode_read_file(argv[1],&p)) return 1; printf("{\"vars\":["); for(i=0;i<p.var_count;i++){ if(i)printf(","); printf("{\"name\":\"%s\",\"value\":",p.vars[i].name); pv(&p.vars[i].value); printf("}"); } printf("],\"commands\":["); for(i=0;i<p.command_count;i++){ YaatCommand*c=&p.commands[i]; if(i)printf(","); printf("{\"kind\":%d,\"a\":\"%s\",\"b\":\"%s\",\"stringId\":\"%s\",\"boolValue\":%d,\"intValue\":%d,\"conditionOp\":%d,\"firstChild\":%d,\"childCount\":%d,\"firstElseChild\":%d,\"elseChildCount\":%d}",c->kind,c->a,c->b,c->string_id,c->bool_value,c->int_value,c->condition_op,c->first_child,c->child_count,c->first_else_child,c->else_child_count); } printf("],\"rooms\":["); for(i=0;i<p.room_count;i++){ YaatRoom*r=&p.rooms[i]; if(i)printf(","); printf("{\"id\":\"%s\",\"label\":\"%s\",\"color\":%lu,\"events\":[",r->id,r->label,r->color); for(j=0;j<r->event_count;j++){ if(j)printf(","); printf("{\"name\":\"%s\",\"item\":\"%s\",\"firstCommand\":%d,\"commandCount\":%d}",r->events[j].name,r->events[j].item,r->events[j].first_command,r->events[j].command_count);} printf("],\"entities\":["); for(j=0;j<r->entity_count;j++){ YaatEntity*e=&r->entities[j]; if(j)printf(","); printf("{\"kind\":%d,\"id\":\"%s\",\"name\":\"%s\",\"x\":%d,\"y\":%d,\"w\":%d,\"h\":%d,\"visible\":%d,\"events\":[",e->kind,e->id,e->name,e->x,e->y,e->w,e->h,e->visible?1:0); for(k=0;k<e->event_count;k++){ if(k)printf(","); printf("{\"name\":\"%s\",\"item\":\"%s\",\"firstCommand\":%d,\"commandCount\":%d}",e->events[k].name,e->events[k].item,e->events[k].first_command,e->events[k].command_count);} printf("]}"); } printf("]}"); } printf("]}\n"); return 0; }
